class Solution2(object):
    def sortArray(self, nums, pre):
        """
        :type nums: List[int]
        :type pre: List[int]
        :rtype: int
        """
        def bfs(start, target):
            lookup = {start}
            q = [start]
            steps = 0
            while q:
                new_q = []
                for x in q:
                    if x == target:
                        return steps
                    for i in pre:
                        nx = tuple(reversed(x[:i]))+x[i:]
                        if nx in lookup:
                            continue
                        lookup.add(nx)
                        new_q.append(nx)
                q = new_q
                steps += 1
            return -1

        return bfs(tuple(nums), tuple(xrange(len(nums))))
